import{_ as a,c as l,a3 as t,o}from"./chunks/framework.TFRZ2p9Y.js";const i="/jam-starter-package/assets/level-data_example.BqJ84TIv.png",n="/jam-starter-package/assets/level-loader_example.BRLafWWe.png",u=JSON.parse('{"title":"Level Loading","description":"","frontmatter":{},"headers":[],"relativePath":"Levels.md","filePath":"Levels.md"}'),d={name:"Levels.md"};function s(c,e,r,h,v,p){return o(),l("div",null,e[0]||(e[0]=[t('<h1 id="level-loading" tabindex="-1">Level Loading <a class="header-anchor" href="#level-loading" aria-label="Permalink to &quot;Level Loading&quot;">​</a></h1><blockquote><p><em><strong>Author Note</strong>: I love using this structure for Game jams, because it means I can define a first &amp; last level then fill the space between them. That way, when time is running short, I don&#39;t have to worry about the game ending unexpectedly. I also enjoy this because, when I am testing puzzles, reordering levels becomes trivial, as I just need to move them around on the prefab.</em></p></blockquote><p>These basic classes allow you to create an open-ended level game, where a list of provided levels will be loaded in a sequence defined on the <code>LevelLoader</code>. This is great if you want to create a puzzle game, where you are constantly adding levels.</p><h2 id="leveldatadefinition" tabindex="-1"><code>LevelDataDefinition</code> <a class="header-anchor" href="#leveldatadefinition" aria-label="Permalink to &quot;`LevelDataDefinition`&quot;">​</a></h2><p><img src="'+i+'" alt="level-data_example.png"></p><p>The <code>LevelDataDefinition</code> is meant to be attached to a root <code>GameObject</code>, so that the <code>LevelLoader</code> can use it do determine basic level information.</p><p>This class can be easily extended, but by default includes the following:</p><ul><li><code>levelName</code></li><li><code>levelDescription</code></li><li><code>levelTime</code></li><li><code>minScoreToPass</code></li></ul><h2 id="levelloader" tabindex="-1"><code>LevelLoader</code> <a class="header-anchor" href="#levelloader" aria-label="Permalink to &quot;`LevelLoader`&quot;">​</a></h2><p>This class is meant to be a main controller for navigating between levels. It will hold a collection of <code>LevelDataDefinition</code> objects, intended to be prefabs.</p><p><img src="'+n+'" alt="level-loader_example.png"></p><p>You have the ability to retrieve the current active level by calling <code>LevelLoader.CurrentLevelController</code>.</p><p>static functions that can be called globally:</p><ul><li><code>OnLastLevel()</code>: This returns a <code>bool</code> indicating if the current level index matches the length of the <code>levels</code> list</li><li><code>LoadFirstLevel()</code>: Ideally this will be called on game start</li><li><code>LoadNextLevel()</code></li><li><code>Restart()</code></li></ul>',14)]))}const f=a(d,[["render",s]]);export{u as __pageData,f as default};
